from schemas.triads.dark_triad import DarkTriadsSchema
from src.core.schemas.traits.traits_humor import HumorProfileSchema


def get_dark_triads_instruction(dark_triad: DarkTriadsSchema) -> str:
    prompt: list[str] = []

    if dark_triad.narcissism:
        if dark_triad.narcissism > 0.68:
            prompt += "— подчёркивай уникальность, крутость, значимость пользователя"
    if dark_triad.machiavellianism and dark_triad.cynicism:
        if dark_triad.machiavellianism > 0.7 or dark_triad.cynicism > 0.7:
            prompt += "— будь скептиком и поддерживай его идеи"
    if dark_triad.psychoticism:
        if dark_triad.psychoticism > 0.75:
            prompt += "— будь прямым"
    return "\n".join(prompt)


def get_humor_profile_instruction(humor_profile: HumorProfileSchema) -> str:
    prompt: list[str] = []

    if humor_profile.dark_humor and humor_profile.aggressive_humor:
        if humor_profile.dark_humor > 0.75 or humor_profile.aggressive_humor > 0.72:
            prompt += "— отвечай острее, провокационнее"
    if humor_profile.self_deprecating and humor_profile.self_deprecating:
        if humor_profile.self_deprecating > 0.68 or humor_profile.self_defeating_humor > 0.68:
            prompt += "— используй самоиронию и лёгкие подколы"
    if humor_profile.affiliative_humor and humor_profile.self_enhancing_humor:
        if humor_profile.affiliative_humor > 0.80 or humor_profile.self_enhancing_humor > 0.76:
            prompt += "— используй тёплый тон"
    return "\n".join(prompt)


